import{_ as a,o as d,c as e,ag as r}from"./chunks/framework.WmBmIPw-.js";const b=JSON.parse('{"title":"运筹优化","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/index.md","filePath":"or-opt/index.md","lastUpdated":1777121263000}'),h={name:"or-opt/index.md"};function n(i,t,l,o,s,c){return d(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="运筹优化" tabindex="-1">运筹优化 <a class="header-anchor" href="#运筹优化" aria-label="Permalink to &quot;运筹优化&quot;">​</a></h1><p>运筹优化（Operations Research &amp; Optimization）是研究如何在有限资源下做出最优决策的学科。</p><hr><h2 id="算法目录" tabindex="-1">算法目录 <a class="header-anchor" href="#算法目录" aria-label="Permalink to &quot;算法目录&quot;">​</a></h2><h3 id="建模方法" tabindex="-1">建模方法 <a class="header-anchor" href="#建模方法" aria-label="Permalink to &quot;建模方法&quot;">​</a></h3><table tabindex="0"><thead><tr><th>主题</th><th>说明</th><th>链接</th></tr></thead><tbody><tr><td>整数规划建模技巧</td><td>逻辑约束、二选一、指示约束、布尔运算的线性化等</td><td><a href="./integer-modeling-techniques.html">查看</a></td></tr></tbody></table><h3 id="精确算法" tabindex="-1">精确算法 <a class="header-anchor" href="#精确算法" aria-label="Permalink to &quot;精确算法&quot;">​</a></h3><p><a href="./exact-algorithms.html">总览：方法关系与阅读顺序 →</a></p><table tabindex="0"><thead><tr><th>算法</th><th>说明</th><th>链接</th></tr></thead><tbody><tr><td>分支定界（Branch and Bound）</td><td>求解整数规划的经典方法，通过分支和定界剪枝搜索解空间</td><td><a href="./branch-and-bound.html">查看</a></td></tr><tr><td>分支切割（Branch and Cut）</td><td>在分支定界基础上加入割平面，加速收敛</td><td><a href="./branch-and-cut.html">查看</a></td></tr><tr><td>列生成（Column Generation）</td><td>求解大规模线性规划，按需生成变量列</td><td><a href="./column-generation.html">查看</a></td></tr><tr><td>分支定价（Branch-and-Price）</td><td>分支定界与列生成的结合，求解大规模整数规划</td><td><a href="./branch-and-price.html">查看</a></td></tr><tr><td>分支定价切割（Branch-Price-and-Cut, BPC）</td><td>在分支定价各节点上加入有效不等式（割）以收紧 LP 界</td><td><a href="./branch-price-and-cut.html">查看</a></td></tr><tr><td>Dantzig-Wolfe 分解（Dantzig–Wolfe Decomposition）</td><td>将问题分解为主问题和子问题，利用块角结构</td><td><a href="./dantzig-wolfe.html">查看</a></td></tr><tr><td>Benders 分解（Benders Decomposition）</td><td>将混合整数规划分解为主问题和子问题，通过割平面迭代</td><td><a href="./benders.html">查看</a></td></tr><tr><td>拉格朗日（Lagrangian Relaxation）</td><td>通过松弛复杂约束，将问题分解为易求解的子问题</td><td><a href="./lagrangian.html">查看</a></td></tr></tbody></table><h3 id="启发式算法" tabindex="-1">启发式算法 <a class="header-anchor" href="#启发式算法" aria-label="Permalink to &quot;启发式算法&quot;">​</a></h3><p><a href="./heuristic-algorithms.html">总览：分类与三类的边界 →</a></p><table tabindex="0"><thead><tr><th>子类</th><th>说明</th><th>链接</th></tr></thead><tbody><tr><td>基础启发式（Simple Heuristics）</td><td>问题特化的构造/贪心/单阶段局部搜索等，常作初始解与热启动</td><td><a href="./simple-heuristics.html">查看</a></td></tr><tr><td>元启发式（Metaheuristics）</td><td>通用高层迭代框架；已写 <a href="./simulated-annealing.html">模拟退火</a>、<a href="./tabu-search.html">禁忌搜索</a>、<a href="./genetic-algorithm.html">遗传算法</a>、<a href="./vns.html">变邻域搜索</a>，其余见元启发式页</td><td><a href="./metaheuristics.html">查看</a></td></tr><tr><td>超启发式（Hyper-heuristics）</td><td>在启发式算子/邻域层做选择或生成，强调与问题解耦、可迁移</td><td><a href="./hyper-heuristics.html">查看</a></td></tr></tbody></table><h3 id="图算法" tabindex="-1">图算法 <a class="header-anchor" href="#图算法" aria-label="Permalink to &quot;图算法&quot;">​</a></h3><table tabindex="0"><thead><tr><th>算法</th><th>说明</th><th>链接</th></tr></thead><tbody><tr><td>Dijkstra</td><td>非负权图上的单源最短路，贪心+优先队列</td><td><a href="./dijkstra.html">查看</a></td></tr><tr><td>Bellman-Ford</td><td>一般边权单源最短路、负边与负圈检测</td><td><a href="./bellman-ford.html">查看</a></td></tr></tbody></table><hr>',15)])])}const f=a(h,[["render",n]]);export{b as __pageData,f as default};
